-- anthropic_content_blocks
DROP TABLE IF EXISTS `anthropic_content_blocks`;
CREATE TABLE anthropic_content_blocks (
    message_uuid    VARCHAR(64)  NOT NULL,
    block_index     INT          NOT NULL,
    type            VARCHAR(64),
    text            LONGTEXT,
    start_timestamp VARCHAR(40),
    stop_timestamp  VARCHAR(40),
    raw_json        JSON         NOT NULL,
    source          VARCHAR(16)  NOT NULL DEFAULT 'export',
    PRIMARY KEY (message_uuid, block_index)
);

INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('10000001-1701-4d00-8000-000000010001', 0, 'text', 'Computer, why does the replicator give weak Earl Grey at quarters preset 4?', '2369-04-12T09:15:00.000000+00:00', '2369-04-12T09:15:00.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-12T09:15:00.000000+00:00","stop_timestamp":"2369-04-12T09:15:00.000000+00:00","text":"Computer, why does the replicator give weak Earl Grey at quarters preset 4?","type":"text"}', 'export');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('10000002-1701-4d00-8000-000000010002', 0, 'text', 'Preset 4 caps tannin extraction at 38%. Try preset 7 (the canonical "hot") which targets 52% and 88°C.', '2369-04-12T09:15:25.000000+00:00', '2369-04-12T09:15:30.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-12T09:15:25.000000+00:00","stop_timestamp":"2369-04-12T09:15:30.000000+00:00","text":"Preset 4 caps tannin extraction at 38%. Try preset 7 (the canonical \\"hot\\") which targets 52% and 88°C.","type":"text"}', 'export');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('10000003-1701-4d00-8000-000000010003', 0, 'text', 'Engage. Thank you.', '2369-04-12T09:18:30.000000+00:00', '2369-04-12T09:18:30.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-12T09:18:30.000000+00:00","stop_timestamp":"2369-04-12T09:18:30.000000+00:00","text":"Engage. Thank you.","type":"text"}', 'export');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('20000001-1701-4d00-8000-000000020001', 0, 'text', 'Attached the conduit telemetry. Why is conduit 17 oscillating at 0.4 Hz?', '2369-04-13T14:02:00.000000+00:00', '2369-04-13T14:02:00.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-13T14:02:00.000000+00:00","stop_timestamp":"2369-04-13T14:02:00.000000+00:00","text":"Attached the conduit telemetry. Why is conduit 17 oscillating at 0.4 Hz?","type":"text"}', 'export');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('20000002-1701-4d00-8000-000000020002', 0, 'text', 'The 0.4Hz is a beat frequency between the EPS regulator (750.0Hz) and the dilithium chamber harmonic (750.4Hz). Re-tune the regulator to 750.2Hz to null it out.', '2369-04-13T14:05:00.000000+00:00', '2369-04-13T14:05:11.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-13T14:05:00.000000+00:00","stop_timestamp":"2369-04-13T14:05:11.000000+00:00","text":"The 0.4Hz is a beat frequency between the EPS regulator (750.0Hz) and the dilithium chamber harmonic (750.4Hz). Re-tune the regulator to 750.2Hz to null it out.","type":"text"}', 'export');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('30000001-1701-4d00-8000-000000030001', 0, 'text', 'Look up the Klingon greeting "nuqneH" and propose a respectful opening line for a diplomatic dispatch to Chancellor K''mpec.', '2369-04-14T10:00:00.000000+00:00', '2369-04-14T10:00:00.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-14T10:00:00.000000+00:00","stop_timestamp":"2369-04-14T10:00:00.000000+00:00","text":"Look up the Klingon greeting \\"nuqneH\\" and propose a respectful opening line for a diplomatic dispatch to Chancellor K''mpec.","type":"text"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('30000002-1701-4d00-8000-000000030002', 0, 'thinking', NULL, '2369-04-14T10:00:30.000000+00:00', '2369-04-14T10:00:31.000000+00:00', '{"cut_off":false,"start_timestamp":"2369-04-14T10:00:30.000000+00:00","stop_timestamp":"2369-04-14T10:00:31.000000+00:00","summaries":[{"summary":"Verifying register of nuqneH before recommending."}],"thinking":"\\"nuqneH\\" literally means \\"what do you want\\" — it''s blunt by Federation standards but standard among Klingons. I should fetch a phrasebook to confirm register before recommending an opening.","truncated":false,"type":"thinking"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('30000002-1701-4d00-8000-000000030002', 1, 'tool_use', NULL, '2369-04-14T10:00:32.000000+00:00', '2369-04-14T10:00:32.000000+00:00', '{"icon_name":"globe","id":"toolu_FAKE0001ngfedcba9876543210","input":{"url":"https://memory-alpha.test/wiki/Klingon_language"},"integration_name":"Web Fetch","message":"Fetching: Klingon language reference","name":"web_fetch","start_timestamp":"2369-04-14T10:00:32.000000+00:00","stop_timestamp":"2369-04-14T10:00:32.000000+00:00","type":"tool_use"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('30000002-1701-4d00-8000-000000030002', 2, 'tool_result', NULL, NULL, NULL, '{"content":[{"is_missing":false,"metadata":{"site_domain":"memory-alpha.test"},"text":"nuqneH (lit. \\"what do you want\\") is the standard Klingon greeting. In formal diplomatic contexts it is paired with the honorific \\"qaleghneS\\" (\\"I am honored to see you\\").","title":"Klingon language — Memory Alpha (test mirror)","type":"knowledge","url":"https://memory-alpha.test/wiki/Klingon_language"}],"is_error":false,"name":"web_fetch","tool_use_id":"toolu_FAKE0001ngfedcba9876543210","type":"tool_result"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('30000002-1701-4d00-8000-000000030002', 3, 'text', 'For a dispatch to Chancellor K''mpec, open with "qaleghneS, Chancellor — nuqneH?" ("I am honored to see you — what do you want?"). The honorific softens the bluntness of nuqneH; together they read as warm-but-direct, which Klingons respect.', '2369-04-14T10:00:55.000000+00:00', '2369-04-14T10:01:00.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-14T10:00:55.000000+00:00","stop_timestamp":"2369-04-14T10:01:00.000000+00:00","text":"For a dispatch to Chancellor K''mpec, open with \\"qaleghneS, Chancellor — nuqneH?\\" (\\"I am honored to see you — what do you want?\\"). The honorific softens the bluntness of nuqneH; together they read as warm-but-direct, which Klingons respect.","type":"text"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('30000003-1701-4d00-8000-000000030003', 0, 'text', 'Perfect. Make it so.', '2369-04-14T10:02:00.000000+00:00', '2369-04-14T10:02:00.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-14T10:02:00.000000+00:00","stop_timestamp":"2369-04-14T10:02:00.000000+00:00","text":"Perfect. Make it so.","type":"text"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('40000001-1701-4d00-8000-000000040001', 0, 'text', 'What''s wrong with this medical-tricorder readout?', '2369-04-15T08:30:00.000000+00:00', '2369-04-15T08:30:00.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-15T08:30:00.000000+00:00","stop_timestamp":"2369-04-15T08:30:00.000000+00:00","text":"What''s wrong with this medical-tricorder readout?","type":"text"}', 'api');
INSERT INTO `anthropic_content_blocks` (`message_uuid`, `block_index`, `type`, `text`, `start_timestamp`, `stop_timestamp`, `raw_json`, `source`) VALUES ('40000002-1701-4d00-8000-000000040002', 0, 'text', 'The readout shows elevated isoboramine (62 ng/mL; reference 35–40) and depressed serotonin uptake. Consistent with early-stage Vulcan neuro-pressure deficit. Recommend mind-meld therapy at 24h intervals.', '2369-04-15T08:30:30.000000+00:00', '2369-04-15T08:30:45.000000+00:00', '{"citations":[],"start_timestamp":"2369-04-15T08:30:30.000000+00:00","stop_timestamp":"2369-04-15T08:30:45.000000+00:00","text":"The readout shows elevated isoboramine (62 ng/mL; reference 35–40) and depressed serotonin uptake. Consistent with early-stage Vulcan neuro-pressure deficit. Recommend mind-meld therapy at 24h intervals.","type":"text"}', 'api');
